    $router->add('GET','/api/v1/system/dashboard',ProtectRoute::wrap($auth, $dashboard->dashboard(...))); $router->add('GET','/api/v1/system/configuration',ProtectRoute::wrap($auth, $dashboard->configuration(...)));
