    $router->add('GET','/api/v1/system/departments',ProtectRoute::wrap($auth, $departments->index(...))); $router->add('POST','/api/v1/system/departments',ProtectRoute::wrap($auth, $departments->store(...))); $router->add('GET','/api/v1/system/departments/{id}',ProtectRoute::wrap($auth, $departments->show(...))); $router->add('PUT','/api/v1/system/departments/{id}',ProtectRoute::wrap($auth, $departments->update(...))); $router->add('DELETE','/api/v1/system/departments/{id}',ProtectRoute::wrap($auth, $departments->destroy(...))); $router->add('POST','/api/v1/system/departments/{id}/activate',ProtectRoute::wrap($auth, $departments->activate(...))); $router->add('POST','/api/v1/system/departments/{id}/deactivate',ProtectRoute::wrap($auth, $departments->deactivate(...)));
